const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Bloque B: Validar y Normalizar Input (sin escritura) ===
// AJUSTAR: mapa de nombre de cabaña (etiqueta visible del form) -> id real en TU base.
const MAP_CABANA = { "Cabana A":1, "Cabana B":2, "Cabana C":3 };
// AJUSTAR: capacidad maxima por id de cabaña (UX temprana; la defensa real es el motor SQL).
const MAP_CAP    = { 1:4, 2:4, 3:4 };
// AJUSTAR: operadores (etiqueta visible -> string normalizado para trazabilidad).
const MAP_OP     = { "Operador 1":"operador_1", "Operador 2":"operador_2" };
// canal_origen: CHECK pre_reservas acepta SOLO whatsapp/instagram/web/manual.
// Etiqueta visible -> { val: string persistido, fino: etiqueta fina para notas si aplica }
const MAP_CANAL_ORIGEN = {
  "WhatsApp":  { val: "whatsapp",  fino: null },
  "Instagram": { val: "instagram", fino: null },
  "Directo":   { val: "manual",    fino: "Directo" },
  "Referido":  { val: "manual",    fino: "Referido" },
  "Airbnb":    { val: "web",       fino: "Airbnb" },
  "Booking":   { val: "web",       fino: "Booking" },
  "Otro":      { val: "manual",    fino: "Otro" }
};
// canal_pago_esperado y medio_pago: CHECK acepta transferencia_bancaria/transferencia_mp/mp_link/cripto/efectivo.
const MAP_CANAL_PAGO = {
  "Transferencia bancaria":     "transferencia_bancaria",
  "Transferencia MercadoPago":  "transferencia_mp",
  "Link MercadoPago":           "mp_link",
  "Efectivo":                   "efectivo",
  "Cripto":                     "cripto"
};
const MAP_MEDIO_PAGO = {
  "Transferencia bancaria":     "transferencia_bancaria",
  "Transferencia MercadoPago":  "transferencia_mp",
  "Link MercadoPago":           "mp_link",
  "Efectivo":                   "efectivo",
  "Cripto":                     "cripto"
};

// 'hoy' en America/Argentina/Buenos_Aires como 'YYYY-MM-DD' (explícito, sin corrimientos)
function hoyBuenosAires() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Argentina/Buenos_Aires',
    year: 'numeric', month: '2-digit', day: '2-digit'
  }).formatToParts(new Date());
  const y = parts.find(p => p.type === 'year').value;
  const m = parts.find(p => p.type === 'month').value;
  const d = parts.find(p => p.type === 'day').value;
  return `${y}-${m}-${d}`;   // en-CA ya da YYYY-MM-DD, pero lo reconstruimos explícito
}

const f = $json;
const operador_label = nv(f["Operador"]);
const cabana_label   = nv(f["Cabaña"]);
const fecha_in       = nv(f["Fecha de entrada"]);
const fecha_out      = nv(f["Fecha de salida"]);
const personas_in    = nv(f["Personas"]);
const nombre_completo = nv(f["Nombre y apellido"]);
const telefono       = nv(f["Teléfono"]);
const email          = nv(f["Email"]);
const canal_origen_label = nv(f["Canal de origen"]);
const canal_pago_label   = nv(f["Canal de pago esperado"]);
const medio_pago_label   = nv(f["Medio de pago"]);
const total_in       = nv(f["Monto total"]);
const sena_in        = nv(f["Seña"]);
const referencia     = nv(f["Referencia de pago"]);
const ninos          = nv(f["Niños"]);
const notas          = nv(f["Notas"]);

const fail = (msg) => ({ json: { valido: false, msg_error: msg } });

const operador = operador_label ? MAP_OP[operador_label] : null;
const id_cabana = cabana_label ? MAP_CABANA[cabana_label] : null;
const canal_origen_map = canal_origen_label ? MAP_CANAL_ORIGEN[canal_origen_label] : null;
const canal_origen = canal_origen_map ? canal_origen_map.val : null;
const origen_fino = canal_origen_map ? canal_origen_map.fino : null;   // etiqueta fina o null
const canal_pago_esperado = canal_pago_label ? MAP_CANAL_PAGO[canal_pago_label] : null;
const medio_pago = medio_pago_label ? MAP_MEDIO_PAGO[medio_pago_label] : null;

if (!operador) return fail("Falta el operador (quién carga).");
if (!id_cabana) return fail("Falta la cabaña o no se reconoce.");
if (!fecha_in || !fecha_out) return fail("Faltan las fechas de entrada o salida.");
if (!personas_in) return fail("Falta la cantidad de personas.");
if (!nombre_completo) return fail("Falta el nombre y apellido del huésped.");
if (!canal_origen) return fail("Falta el canal de origen.");
if (!canal_pago_esperado) return fail("Falta el canal de pago esperado.");
if (!medio_pago) return fail("Falta el medio de pago.");
if (!total_in) return fail("Falta el monto total.");

const personas = parseInt(personas_in, 10);
if (!Number.isInteger(personas) || personas < 1) return fail("La cantidad de personas no es válida.");
const total = Number(total_in);
if (!(total > 0)) return fail("El monto total debe ser mayor a 0.");

if (!telefono && !email) return fail("Cargá al menos teléfono o email del huésped.");

const hoyStr = hoyBuenosAires();
if (fecha_out <= fecha_in) return fail("La fecha de salida debe ser posterior a la de entrada.");
if (fecha_in < hoyStr) return fail("Las reservas con fechas pasadas o ya iniciadas requieren carga manual; no se cargan por acá.");

const cap = MAP_CAP[id_cabana];
if (personas > cap) return fail("Esa cabaña admite hasta " + cap + " personas.");

// Seña: vacía / 0 / no numérica -> 50% automático. Valor > 0 explícito -> se respeta.
// (n8n puede entregar 0 para un Number vacío; 0 se interpreta como "no cargó seña" -> 50%.
//  El caso de pago 100% se carga como total=X, seña=X, no como seña=0.)
let sena;
const sena_raw = f["Seña"];
const sena_num = (sena_raw === null || sena_raw === undefined || String(sena_raw).trim() === "")
                 ? NaN : Number(sena_raw);
if (Number.isNaN(sena_num) || sena_num === 0) {
  sena = Math.round(total * 0.5 * 100) / 100;     // 50% automático
} else if (sena_num < 0) {
  return fail("La seña no puede ser negativa.");
} else if (sena_num > total) {
  return fail("La seña no puede superar el monto total.");
} else {
  sena = sena_num;                                 // valor explícito > 0
}

// contact_key robusto: teléfono (solo dígitos) o email_<email_min>. Nunca 'sintel'.
let contact_key;
if (telefono) {
  const tel_norm = telefono.replace(/[^\d]/g, "");
  if (!tel_norm) {
    // teléfono presente pero sin dígitos válidos: caer a email si hay
    if (email) { contact_key = "email_" + email.trim().toLowerCase(); }
    else { return fail("El teléfono no tiene dígitos válidos y no hay email."); }
  } else {
    contact_key = tel_norm;
  }
} else {
  // sin teléfono, con email (garantizado por validación de contacto)
  contact_key = "email_" + email.trim().toLowerCase();
}

const idempotency_key = ["ops_8b", id_cabana, fecha_in, fecha_out, contact_key].join("_");
// AJUSTAR: reemplazar <MARCADOR_AMBIENTE> por el de tu entorno (ej: n8n_ops / n8n_test).
const source_event = "<MARCADOR_AMBIENTE>_w8b_carga_" + operador + "_manual";

// Preservar el dato operativo fino (Airbnb/Booking/Directo/Referido/Otro) en notas,
// ya que el CHECK de canal_origen obliga a persistir un valor genérico (web/manual).
let notas_final = notas;
if (origen_fino) {
  const prefijo = "Origen operativo: " + origen_fino;
  notas_final = notas ? (prefijo + " | " + notas) : prefijo;
}

return { json: {
  valido: true,
  operador, id_cabana, cabana_label,
  fecha_in, fecha_out, personas,
  nombre_completo, telefono, email,
  canal_origen, origen_fino, canal_pago_esperado, medio_pago,
  total, sena, saldo: Math.round((total - sena) * 100) / 100,
  referencia, ninos, notas: notas_final,
  contact_key, idempotency_key, source_event,
  id_pre_reserva: null, id_pago: null, id_reserva: null
}};

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Build Payload P1: crear_prereserva ===
const d = $json;
const payload = {
  huesped: { nombre: d.nombre_completo, apellido: "", telefono: nv(d.telefono), email: nv(d.email) },
  id_cabana: d.id_cabana,
  fecha_in: d.fecha_in,
  fecha_out: d.fecha_out,
  personas: d.personas,
  monto_total: d.total,
  monto_sena: d.sena,
  canal_origen: d.canal_origen,
  canal_pago_esperado: d.canal_pago_esperado,
  source_event: d.source_event,
  idempotency_key: d.idempotency_key,
  notas: nv(d.notas),
  ninos: nv(d.ninos)
};
return { json: { payload, ctx: d } };

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Normalize: crear_prereserva ===
const ctx = ($('Build Payload P1') ? JSON.parse(JSON.stringify($('Build Payload P1').item.json.ctx)) : ($json.ctx || {}));
const row = $json;
let br = null, ok = false, error_type = null, raw_error = null;

if (row && row.error) {
  error_type = 'tecnico';
  raw_error = String((row.error && row.error.message) || row.error);
} else {
  br = row["crear_prereserva"] || row.result || null;
  if (typeof br === 'string') { try { br = JSON.parse(br); } catch (e) {} }
  if (!br && row && typeof row === 'object' && ('ok' in row)) { br = row; }
  if (!br) {
    error_type = 'tecnico';
    raw_error = 'respuesta_sql_vacia_o_no_reconocida';
  } else if (br.ok === true) {
    ok = true;
  } else {
    error_type = 'negocio';
  }
}

if (ok && br && br.id_pre_reserva != null) { ctx.id_pre_reserva = br.id_pre_reserva; }

return { json: {
  step: "crear_prereserva", ok, error_type, raw_error,
  business_result: br,
  id_pre_reserva: ctx.id_pre_reserva ?? null,
  id_pago: ctx.id_pago ?? null,
  id_reserva: ctx.id_reserva ?? null,
  ctx
}};

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Build Payload P2: registrar_pago ===
const prev = $json;                 // viene de Normalize C
const ctx = prev.ctx;               // ctx ya trae id_pre_reserva enriquecido
const payload = {
  id_pre_reserva: ctx.id_pre_reserva,
  tipo: "sena",
  medio_pago: ctx.medio_pago,
  monto_esperado: ctx.sena,
  monto_recibido: ctx.sena,
  estado_inicial: "confirmado",
  referencia_externa: nv(ctx.referencia),
  validado_por: ctx.operador,
  source_event: ctx.source_event
};
return { json: { payload, ctx } };

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Normalize: registrar_pago ===
const ctx = ($('Build Payload P2') ? JSON.parse(JSON.stringify($('Build Payload P2').item.json.ctx)) : ($json.ctx || {}));
const row = $json;
let br = null, ok = false, error_type = null, raw_error = null;

if (row && row.error) {
  error_type = 'tecnico';
  raw_error = String((row.error && row.error.message) || row.error);
} else {
  br = row["registrar_pago"] || row.result || null;
  if (typeof br === 'string') { try { br = JSON.parse(br); } catch (e) {} }
  if (!br && row && typeof row === 'object' && ('ok' in row)) { br = row; }
  if (!br) {
    error_type = 'tecnico';
    raw_error = 'respuesta_sql_vacia_o_no_reconocida';
  } else if (br.ok === true) {
    ok = true;
  } else {
    error_type = 'negocio';
  }
}

if (br && br.id_pago != null) { ctx.id_pago = br.id_pago; }
// REGLA ESTRICTA D-8B-15: ok:true no basta; debe ser estado 'confirmado' y SIN warning.
if (ok && br) {
  const estado_ok = (br.estado === 'confirmado');
  const sin_warning = !br.warning;
  if (!(estado_ok && sin_warning)) {
    ok = false;
    error_type = 'negocio';   // anómalo: pago registrado pero no confirmado
  }
}

return { json: {
  step: "registrar_pago", ok, error_type, raw_error,
  business_result: br,
  id_pre_reserva: ctx.id_pre_reserva ?? null,
  id_pago: ctx.id_pago ?? null,
  id_reserva: ctx.id_reserva ?? null,
  ctx
}};

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Build Payload P3: confirmar_reserva ===
const prev = $json;                 // viene de Normalize P2
const ctx = prev.ctx;               // ctx trae id_pre_reserva y id_pago
const payload = {
  id_pre_reserva: ctx.id_pre_reserva,
  permitir_pago_en_revision: false,
  created_by: ctx.operador,
  encargado_semana: "",
  source_event: ctx.source_event
};
return { json: { payload, ctx } };

const nv = (v) => { if (v === undefined || v === null) return null; const s = String(v).trim(); return s === '' ? null : s; };

// === Normalize: confirmar_reserva ===
const ctx = ($('Build Payload P3') ? JSON.parse(JSON.stringify($('Build Payload P3').item.json.ctx)) : ($json.ctx || {}));
const row = $json;
let br = null, ok = false, error_type = null, raw_error = null;

if (row && row.error) {
  error_type = 'tecnico';
  raw_error = String((row.error && row.error.message) || row.error);
} else {
  br = row["confirmar_reserva"] || row.result || null;
  if (typeof br === 'string') { try { br = JSON.parse(br); } catch (e) {} }
  if (!br && row && typeof row === 'object' && ('ok' in row)) { br = row; }
  if (!br) {
    error_type = 'tecnico';
    raw_error = 'respuesta_sql_vacia_o_no_reconocida';
  } else if (br.ok === true) {
    ok = true;
  } else {
    error_type = 'negocio';
  }
}

if (ok && br && br.id_reserva != null) { ctx.id_reserva = br.id_reserva; }

return { json: {
  step: "confirmar_reserva", ok, error_type, raw_error,
  business_result: br,
  id_pre_reserva: ctx.id_pre_reserva ?? null,
  id_pago: ctx.id_pago ?? null,
  id_reserva: ctx.id_reserva ?? null,
  ctx
}};

// === Build Compensation Context (unifica fallo P2 y fallo P3) ===
const prev = $json;                 // Normalize P2 (rama F) o Normalize P3 (rama G)
const ctx = prev.ctx || {};
const failed_step = prev.step;      // 'registrar_pago' | 'confirmar_reserva'
const id_pre_reserva = ctx.id_pre_reserva ?? prev.id_pre_reserva ?? null;
const id_pago = ctx.id_pago ?? prev.id_pago ?? null;
const pago_registrado = (failed_step === 'confirmar_reserva') ? true : (id_pago != null);
const failure_reason = (prev.error_type === 'tecnico')
  ? ('tecnico: ' + (prev.raw_error || 'desconocido'))
  : ('negocio: ' + (prev.business_result ? (prev.business_result.error || JSON.stringify(prev.business_result)) : 'desconocido'));
return { json: {
  payload: {
    id_pre_reserva: id_pre_reserva,
    motivo: "cliente",
    descripcion: "rollback_8b_fallo_cadena",
    source_event: ctx.source_event || "<MARCADOR_AMBIENTE>_w8b_carga_desconocido_manual"
  },
  compensation_context: { id_pre_reserva, id_pago, failed_step, failure_reason, pago_registrado, raw_result: prev },
  ctx
}};

// === Normalize I: normaliza SOLO el resultado técnico de cancelar_prereserva ===
const row = $json;
const compCtx = ($('Build Compensation Context') ? $('Build Compensation Context').item.json.compensation_context : null);
const ctx = ($('Build Compensation Context') ? $('Build Compensation Context').item.json.ctx : null);
let cancelacion_ok = false, pagos_asociados_count = null, pagos_asociados_ids = null;
let estado_no_cancelable = false, error_type = null, raw_error = null, br = null;

if (row && row.error) {
  error_type = 'tecnico';
  raw_error = String((row.error && row.error.message) || row.error);
} else {
  br = row.cancelar_prereserva || row.result || null;
  if (typeof br === 'string') { try { br = JSON.parse(br); } catch (e) {} }
  if (!br && row && typeof row === 'object' && ('ok' in row)) { br = row; }
  if (!br) {
    error_type = 'tecnico';
    raw_error = 'respuesta_sql_vacia_o_no_reconocida';
  } else if (br.ok === true) {
    cancelacion_ok = true;
    pagos_asociados_count = br.pagos_asociados_count ?? null;
    pagos_asociados_ids = br.pagos_asociados_ids ?? null;
  } else {
    error_type = 'negocio';
    if (br.error === 'estado_no_cancelable') estado_no_cancelable = true;
  }
}
return { json: {
  step: "cancelar_prereserva",
  cancelacion_ok, pagos_asociados_count, pagos_asociados_ids,
  estado_no_cancelable, error_type, raw_error,
  compensation_context: compCtx, ctx
}};

// === Build Response: ÚNICA fuente de la decisión del mensaje ===
// Emite { resultado, completionTitle, completionMessage } que consume el nodo Form Ending.
const j = $json;
function out(tipo, titulo, detalle) {
  return { json: { resultado: tipo, completionTitle: titulo, completionMessage: detalle } };
}

// 1) Validación fallida (Bloque B)
if (j.valido === false) return out("error_validacion", "No se pudo cargar", j.msg_error);

// 2) Éxito (rama G-ok: confirmar_reserva ok)
if (j.ok === true && j.step === "confirmar_reserva") {
  const ctx = j.ctx || {};
  const det = "Reserva N° " + (ctx.id_reserva ?? j.id_reserva) + ". " + (ctx.cabana_label||"") + " " +
              (ctx.fecha_in||"") + " → " + (ctx.fecha_out||"") +
              ". Saldo pendiente: $" + (ctx.saldo!=null?ctx.saldo:"-") + ".";
  return out("ok", "✅ Reserva confirmada", det);
}

// 3) Error en P1 (Normalize C, ok:false)
if (j.step === "crear_prereserva" && j.ok === false) {
  if (j.error_type === "tecnico")
    return out("error_tecnico", "⚠️ Error técnico",
      "No se pudo procesar la carga. Reintentá en un momento; si persiste, avisá al responsable.");
  const e = j.business_result ? j.business_result.error : null;
  const MAP = {
    payload_invalido: "Faltan datos obligatorios (revisá los campos).",
    precio_requerido: "Faltan el monto total o la seña.",
    fechas_invalidas: "La fecha de salida debe ser posterior a la de entrada.",
    huesped_nombre_requerido: "Falta el nombre del huésped.",
    huesped_contacto_requerido: "Cargá al menos teléfono o email.",
    cabana_no_existe: "Esa cabaña no está disponible para cargar.",
    cabana_inactiva: "Esa cabaña no está disponible para cargar.",
    excede_capacidad: "Esa cabaña no admite esa cantidad de personas.",
    no_disponible: "Esa cabaña ya está ocupada en esas fechas.",
    hora_fuera_de_rango: "El horario solicitado está fuera del rango permitido."
  };
  return out("error_negocio", "No se pudo cargar", MAP[e] || ("No se pudo crear la reserva (" + (e||"error") + ")."));
}

// 4) Resultado de compensación (Normalize I)
if (j.step === "cancelar_prereserva") {
  const cc = j.compensation_context || {};
  const idp = cc.id_pre_reserva;
  const ids = (j.pagos_asociados_ids && j.pagos_asociados_ids.length) ? j.pagos_asociados_ids.join(", ") : null;
  if (j.cancelacion_ok === true && j.pagos_asociados_count === 0)
    return out("reversion_limpia", "No se completó la carga",
      "La carga no se pudo completar (" + (cc.failure_reason||"") + "). " +
      "La pre-reserva se canceló y no quedó ningún pago registrado. Podés reintentar.");
  if (j.cancelacion_ok === true && j.pagos_asociados_count > 0)
    return out("revision_manual", "⚠️ Requiere revisión manual",
      "Se registró un pago pero no se pudo confirmar la reserva. La pre-reserva #" + idp +
      " se canceló pero el/los pago/s siguen registrados (#" + ids + "). Avisá al responsable con esos números.");
  const pagoTxt = cc.id_pago ? (", pago #" + cc.id_pago) : "";
  return out("estado_parcial", "⚠️ Carga incompleta",
    "La carga quedó incompleta (pre-reserva #" + idp + pagoTxt + ") y no se pudo revertir automáticamente. " +
    "Requiere revisión manual — avisá al responsable.");
}

// 5) Fallback defensivo
return out("error_tecnico", "⚠️ Error inesperado",
  "No se pudo determinar el resultado de la carga. Avisá al responsable.");
